class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.process_priority = process_priority

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _apply_process_priority(self, pid: int) -> None:
        """Best-effort attempt to apply ``self.process_priority`` to the
        given process id. Any failure, or an unsupported/unknown priority
        value, is silently ignored so the edit operation never fails
        because of this.
        """
        if self.process_priority is None:
            return

        if WIN:
            priority_class = _WIN_PRIORITY_CLASSES.get(self.process_priority)
            if priority_class is None:
                return
            try:
                import ctypes

                handle = ctypes.windll.kernel32.OpenProcess(  # type: ignore[attr-defined]
                    0x0200 | 0x0400, False, pid  # PROCESS_SET_INFORMATION | QUERY
                )
                if handle:
                    try:
                        ctypes.windll.kernel32.SetPriorityClass(  # type: ignore[attr-defined]
                            handle, priority_class
                        )
                    finally:
                        ctypes.windll.kernel32.CloseHandle(handle)  # type: ignore[attr-defined]
            except Exception:
                pass
        else:
            nice_value = _UNIX_PRIORITY_NICE_VALUES.get(self.process_priority)
            if nice_value is None:
                return
            try:
                os.setpriority(os.PRIO_PROCESS, pid, nice_value)
            except (AttributeError, OSError, PermissionError):
                pass

    def edit_file(self, filename: str) -> None:
        import subprocess

        editor = self.get_editor()
        environ: dict[str, str] | None = None

        if self.env:
            environ = os.environ.copy()
            environ.update(self.env)

        try:
            c = subprocess.Popen(f'{editor} "{filename}"', env=environ, shell=True)
            self._apply_process_priority(c.pid)
            exit_code = c.wait()
            if exit_code != 0:
                raise ClickException(
                    _("{editor}: Editing failed").format(editor=editor)
                )
        except OSError as e:
            raise ClickException(
                _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
            ) from e"}

